#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int data[105];
    int top;
} Stack;

void init(Stack *s){s->top=-1;}
int isEmpty(Stack *s){return s->top==-1;}
int isFull(Stack *s){return s->top==104;}
void push(Stack *s,int x){if(!isFull(s)) s->data[++s->top]=x;}
int pop(Stack *s){return s->data[s->top--];}
int peek(Stack *s){return s->data[s->top];}

void insertAtBottom(Stack *s,int x){
    if(isEmpty(s)){
        push(s,x);
        return;
    }
    int topElem=pop(s);
    insertAtBottom(s,x);
    push(s,topElem);
}

void reverseStack(Stack *s){
    if(isEmpty(s)) return;
    int topElem=pop(s);
    reverseStack(s);
    insertAtBottom(s,topElem);
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        Stack st; init(&st);
        for(int i=0;i<N;i++){
            int x; scanf("%d",&x);
            push(&st,x); // input order is bottom->top, push preserves that
        }
        reverseStack(&st);
        // extract to array for bottom‑to‑top output
        int out[105]; int idx=0;
        while(!isEmpty(&st)) out[idx++]=pop(&st);
        // out now holds top‑to‑bottom, reverse to get bottom‑to‑top
        for(int i=idx-1;i>=0;i--){
            printf("%d",out[i]);
            if(i) printf(" ");
        }
        if(T) printf("\n");
    }
    return 0;
}

