#include <bits/stdc++.h>
using namespace std;

void insertAtBottom(stack<int> &st,int x){
    if(st.empty()){
        st.push(x);
        return;
    }
    int topElem=st.top(); st.pop();
    insertAtBottom(st,x);
    st.push(topElem);
}

void reverseStack(stack<int> &st){
    if(st.empty()) return;
    int topElem=st.top(); st.pop();
    reverseStack(st);
    insertAtBottom(st,topElem);
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        stack<int> st;
        for(int i=0;i<N;i++){
            int x; cin>>x; st.push(x);
        }
        reverseStack(st);
        vector<int> tmp;
        while(!st.empty()){
            tmp.push_back(st.top()); st.pop();
        }
        for(int i=tmp.size()-1;i>=0;i--){
            cout<<tmp[i];
            if(i) cout<<' ';
        }
        if(T) cout<<'\n';
    }
    return 0;
}

