const fs = require('fs');
const input = fs.readFileSync(0,'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
function insertAtBottom(stack, x){
    if(stack.length===0){
        stack.push(x);
        return;
    }
    const top = stack.pop();
    insertAtBottom(stack, x);
    stack.push(top);
}
function reverseStack(stack){
    if(stack.length===0) return;
    const top = stack.pop();
    reverseStack(stack);
    insertAtBottom(stack, top);
}
for(let tc=0; tc<T; tc++){
    const N = input[idx++];
    const stack = [];
    for(let i=0;i<N;i++) stack.push(input[idx++]); // bottom‑to‑top order
    reverseStack(stack);
    const tmp = [];
    while(stack.length) tmp.push(stack.pop());
